import type { MaybeRefOrGetter } from 'vue'
import { randomStr } from '@antfu/utils'
import { computed, onUnmounted, reactive, toValue } from 'vue'
import { useRouter } from '#app/composables/router'
import { useEnabledTabs } from './state-tabs'

export interface CommandItem {
  id: string
  title: string
  description?: string
  icon?: string
  action: () => void | CommandItem[] | Promise<CommandItem[] | void>
}

const registeredCommands = reactive(new Map<string, MaybeRefOrGetter<CommandItem[]>>())

export function useCommands() {
  const tabs = useEnabledTabs()
  const router = useRouter()

  const fixedCommands: CommandItem[] = [
    {
      id: 'fixed:settings',
      title: 'Settings',
      icon: 'carbon-settings-adjust',
      action: () => {
        router.push('/settings')
      },
    },
    {
      id: 'fixed:docs',
      title: 'Nuxt Documentations',
      icon: 'logos-nuxt-icon',
      action: () => {
        return getNuxtDocsCommands()
      },
    },
  ]

  const tabCommands = computed(() => tabs.value
    .map((i): CommandItem => {
      return {
        id: `tab:${i.name}`,
        title: i.title || i.name,
        icon: i.icon,
        action: () => {
          if ('onClick' in i && i.onClick)
            i.onClick()
          else
            router.push(('path' in i && i.path) ? i.path : `/modules/custom-${i.name}`)
        },
      }
    }))

  return computed(() => {
    return [
      ...fixedCommands,
      ...tabCommands.value,
      ...[...registeredCommands.values()]
        .flatMap(i => toValue(i)),
    ]
  })
}

export function registerCommands(getter: MaybeRefOrGetter<CommandItem[]>) {
  const id = randomStr()

  registeredCommands.set(id, getter)

  onUnmounted(() => {
    registeredCommands.delete(id)
  })
}

let _nuxtDocsCommands: CommandItem[] | undefined

export async function getNuxtDocsCommands() {
  if (!_nuxtDocsCommands) {
    const list = await $fetch<any[]>('https://nuxt.com/api/search.json', {
      query: {
        select: '_path,title,description,navigation',
      },
    })
    _nuxtDocsCommands = list.map(i => ({
      id: i._path,
      title: i.title,
      description: i.description,
      icon: i.navigation?.icon ?? 'i-carbon-document-multiple-01',
      action: () => {
        window.open(`https://nuxt.com/${i._path}`, '_blank')
      },
    }))
  }
  return _nuxtDocsCommands
}

import Fuse from 'fuse.js'

export interface Command {
  id?: string
  title: string | (() => string)
  to?: string
  description?: string
  visible?: () => boolean
  handler?: () => void
  icon?: string
}

export const useCommandsStore = defineStore('commands', () => {
  const search = ref('')
  const isShown = ref(false)
  const commandsAll = reactive<Set<Command>>(new Set())
  const guidesResult = ref<Command[]>([])

  const fuse = computed(() => new Fuse(Array.from(commandsAll), {
    keys: ['title', 'description'],
    threshold: 0.3,
  }))

  const { locale } = useI18n()
  const collection = computed(() => locale.value === 'ja' ? 'ja' : 'en')

  const { data: sections } = useAsyncData('search-sections', () => {
    return queryCollectionSearchSections(collection.value, {
      ignoredTags: ['hidden'],
    })
  })

  const debouncedSearch = refDebounced(search, 100)

  watch(debouncedSearch, async (v) => {
    if (v) {
      guidesResult.value = sections.value
        ?.filter(x => !x.id.includes('#'))
        ?.map((i): Command => ({
          id: i.id,
          title: i.title || 'Untitled',
          to: i.id,
          icon: 'i-ph-file-duotone',
        })) || []
    }
    else {
      guidesResult.value = []
    }
  })

  const commandsResult = computed(() => {
    let result = !search.value
      ? Array.from(commandsAll)
      : [
          ...fuse.value.search(search.value).map(i => i.item),
          ...guidesResult.value,
        ]

    result = result
      .filter(i => i.visible ? i.visible() : true)

    return result
  })

  return {
    search,
    isShown,
    commandsAll,
    commandsResult,
  }
})

export function addCommands(...inputs: Command[]) {
  const commands = useCommandsStore()

  onMounted(() => {
    for (const command of inputs)
      commands.commandsAll.add(command)
  })

  onUnmounted(() => {
    for (const command of inputs)
      commands.commandsAll.delete(command)
  })
}

if (import.meta.hot)
  import.meta.hot.accept(acceptHMRUpdate(useCommandsStore, import.meta.hot))

import type { Filter } from '../types'
import type { Job } from '#shared/types'
import { toRelativeDate } from '../utils'

export const useEnterpriseJobs = () => {
  const route = useRoute()
  const { data: jobs, execute } = useAsyncData('jobs', () => $fetch('/api/jobs'), {
    immediate: false,
    default: () => [],
    transform: (data) => {
      return data.map(job => ({
        ...job,
        remote: mapRemote(job.remote),
        published_at: toRelativeDate(job.published_at)
      }))
    }
  })

  const mapRemote = (remoteType: string) => {
    switch (remoteType) {
      case 'ONLY':
        return 'Remote Only'
      case 'ALLOWED':
        return 'Remote Allowed'
      default:
        return 'Onsite'
    }
  }

  // Data fetching

  async function fetchList() {
    if (jobs.value.length) {
      return
    }

    return execute()
  }

  // Computed

  const filteredJobs = computed<Job[]>(() => {
    return [...jobs.value]
      .filter((job) => {
        if (selectedLocation.value && !job.locations.includes(selectedLocation.value.key as string)) {
          return false
        }
        if (selectedType.value && job.remote !== selectedType.value.key) {
          return false
        }
        return true
      })
  })

  const locations = computed<Filter[]>(() => {
    const locations = jobs.value?.map(job => job.locations).flat() || []
    return [...new Set(locations)]
      .map(l => ({ key: l, label: l }))
      .sort((a, b) => a.label.localeCompare(b.label))
  })

  const types = computed<Filter[]>(() => {
    const types = jobs.value?.map(job => job.remote)
    return [...new Set(types)]
      .map((t) => {
        return { key: t, label: t }
      })
  })

  const selectedLocation = computed(() => {
    return locations.value.find(location => location.key === route.query.location)
  })

  const selectedType = computed(() => {
    return types.value.find(type => type.key === route.query.type)
  })

  return {
    fetchList,
    filteredJobs,
    locations,
    types,
    selectedLocation,
    selectedType
  }
}

import { defineComponent, h } from 'vue'
import type { DefineSetupFnComponent } from 'vue'
import { useLoadingIndicator } from '../composables/loading-indicator'

interface NuxtLoadingIndicatorProps {
  throttle?: number
  duration?: number
  hideDelay?: number
  resetDelay?: number
  height?: number
  color?: string | boolean
  errorColor?: string
  estimatedProgress?: (duration: number, elapsed: number) => number
}

const NuxtLoadingIndicator = defineComponent({
  name: 'NuxtLoadingIndicator',
  props: {
    throttle: {
      type: Number,
      default: 200,
    },
    duration: {
      type: Number,
      default: 2000,
    },
    hideDelay: {
      type: Number,
      default: 500,
    },
    resetDelay: {
      type: Number,
      default: 400,
    },
    height: {
      type: Number,
      default: 3,
    },
    color: {
      type: [String, Boolean],
      default: 'repeating-linear-gradient(to right,#00dc82 0%,#34cdfe 50%,#0047e1 100%)',
    },
    errorColor: {
      type: String,
      default: 'repeating-linear-gradient(to right,#f87171 0%,#ef4444 100%)',
    },
    estimatedProgress: {
      type: Function as unknown as () => (duration: number, elapsed: number) => number,
      required: false,
    },
  },
  setup (props, { slots, expose }) {
    const { progress, isLoading, error, start, finish, clear } = useLoadingIndicator({
      duration: props.duration,
      throttle: props.throttle,
      hideDelay: props.hideDelay,
      resetDelay: props.resetDelay,
      estimatedProgress: props.estimatedProgress,
    })

    expose({
      progress, isLoading, error, start, finish, clear,
    })

    return () => h('div', {
      class: 'nuxt-loading-indicator',
      style: {
        position: 'fixed',
        top: 0,
        right: 0,
        left: 0,
        pointerEvents: 'none',
        width: 'auto',
        height: `${props.height}px`,
        opacity: isLoading.value ? 1 : 0,
        background: error.value ? props.errorColor : props.color || undefined,
        backgroundSize: `${progress.value > 0 ? (100 / progress.value) * 100 : 0}% auto`,
        transform: `scaleX(${progress.value}%)`,
        transformOrigin: 'left',
        transition: 'transform 0.1s, height 0.4s, opacity 0.4s',
        zIndex: 999999,
      },
    }, slots)
  },
}) as unknown as DefineSetupFnComponent<NuxtLoadingIndicatorProps>

export default NuxtLoadingIndicator

