import { Buffer } from 'node:buffer'
import fs from 'node:fs/promises'
import { join } from 'node:path'
import { fileURLToPath } from 'node:url'
import c from 'ansis'
import chokidar from 'chokidar'
import { resolveModulePath } from 'exsolve'
import { transform } from 'lightningcss'
import { glob } from 'tinyglobby'
import { createGenerator } from 'unocss'
import config from '../uno.config'

const SRC_DIR = fileURLToPath(new URL('..', import.meta.url))
const GLOBS = ['components/**/*.vue']
const USER_STYLE = join(SRC_DIR, 'style.css')
const GENERATED_CSS = join(SRC_DIR, '.generated/css.ts')
const MINIFY = true

export async function buildCSS() {
  const reset = await fs.readFile(resolveModulePath('@unocss/reset/tailwind.css'), 'utf-8')
  const files = await glob(GLOBS, {
    cwd: SRC_DIR,
    absolute: true,
  })

  const generater = await createGenerator(config)

  // Extra tokens for UnoCSS
  const tokens = new Set<string>()
  for (const file of files) {
    const content = await fs.readFile(file, 'utf-8')
    await generater.applyExtractors(content, file, tokens)
  }

  // Read user style
  const userStyle = await fs.readFile(USER_STYLE, 'utf-8').catch(() => '')

  const unoResult = await generater.generate(tokens)
  const input = [
    reset,
    userStyle,
    unoResult.css,
  ].join('\n')

  // Minify the CSS with LightningCSS
  try {
    const { code: css } = transform({
      code: Buffer.from(input, 'utf-8'),
      filename: 'style.css',
      targets: {
        chrome: 100,
      },
      minify: MINIFY,
    })
    await fs.writeFile(GENERATED_CSS, [
      `/* eslint-disable eslint-comments/no-unlimited-disable */`,
      `/* eslint-disable */`,
      `export default ${JSON.stringify(String(css))}`,
      '',
    ].join('\n'))
    console.log(`${c.green('✓')} CSS built`)

    return {
      css,
      files,
    }
  }
  catch (e: any) {
    console.error(`${c.red('!')} Failed to build css`, e)
    if (e.loc) {
      console.error('Error at line', e.loc.line, 'column', e.loc.column)
      console.error(input.split('\n')[e.loc.line - 1])
      console.error(`${' '.repeat(e.loc.column - 1)}^`)
    }
  }
}

export async function watchCSS() {
  const watcher = chokidar.watch(join(SRC_DIR, 'components'))
  watcher.on('change', async () => {
    await buildCSS()
  })

  return watcher
}

import { bench, describe } from 'vitest'
import { createLogger, initLogger, shouldKeep } from '../../src/logger'

describe('head sampling', () => {
  bench('no sampling configured', () => {
    initLogger({
      pretty: false,
      silent: true,
      _suppressDrainWarning: true,
    })
    const log = createLogger({ method: 'GET', path: '/api/health' })
    log.emit({ status: 200 })
  })

  bench('with sampling rates', () => {
    initLogger({
      pretty: false,
      silent: true,
      sampling: { rates: { info: 10, warn: 50, debug: 0, error: 100 } },
      _suppressDrainWarning: true,
    })
    const log = createLogger({ method: 'GET', path: '/api/health' })
    log.emit({ status: 200 })
  })
})

describe('tail sampling (shouldKeep)', () => {
  initLogger({
    pretty: false,
    silent: true,
    sampling: {
      rates: { info: 10 },
      keep: [
        { duration: 1000 },
        { status: 400 },
        { path: '/api/critical/**' },
      ],
    },
    _suppressDrainWarning: true,
  })

  bench('no match (fast path)', () => {
    shouldKeep({ status: 200, duration: 50, path: '/api/health', method: 'GET', context: {} })
  })

  bench('status match', () => {
    shouldKeep({ status: 500, duration: 50, path: '/api/health', method: 'GET', context: {} })
  })

  bench('duration match', () => {
    shouldKeep({ status: 200, duration: 2000, path: '/api/health', method: 'GET', context: {} })
  })

  bench('path glob match', () => {
    shouldKeep({ status: 200, duration: 50, path: '/api/critical/checkout', method: 'POST', context: {} })
  })
})

describe('head + tail sampling combined', () => {
  initLogger({
    pretty: false,
    silent: true,
    sampling: {
      rates: { info: 10, warn: 50, debug: 0, error: 100 },
      keep: [
        { duration: 1000 },
        { status: 400 },
        { path: '/api/critical/**' },
      ],
    },
    _suppressDrainWarning: true,
  })

  bench('full emit with sampling (likely sampled out)', () => {
    const log = createLogger({ method: 'GET', path: '/api/health' })
    log.emit({ status: 200 })
  })

  bench('full emit with force-keep (tail sampling hit)', () => {
    const log = createLogger({ method: 'POST', path: '/api/critical/checkout' })
    log.set({ userId: '123' })
    log.emit({ status: 500 })
  })
})

import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { defu } from 'defu'
import type { Nuxt } from '@nuxt/schema'
import { dirname, resolve } from 'pathe'
import escapeStringRegexp from 'escape-string-regexp'

import type { Plugin as RollupPlugin } from 'rollup'
import type { Plugin as VitePlugin } from 'vite'

export const SourcemapPreserverPlugin = (nuxt: Nuxt): VitePlugin | VitePlugin[] => {
  let outputDir: string
  const ids = new Set<string>()

  if (!nuxt.options.sourcemap.server || nuxt.options.dev) {
    return []
  }

  const nitroPlugin = () => ({
    name: 'nuxt:sourcemap-import',
    load: {
      filter: {
        id: new RegExp('^(\\w:)?' + escapeStringRegexp(outputDir.replace(/\/?$/, '/')).replace(/\//g, '[\\\\/]')),
      },
      async handler (id) {
        id = resolve(id)
        if (!ids.has(id)) { return }

        const [code, map] = await Promise.all([
          readFile(id, 'utf-8').catch(() => undefined),
          readFile(id + '.map.json', 'utf-8').catch(() => undefined),
        ])

        if (!code) {
          this.warn('Failed loading file')
          return null
        }

        return {
          code,
          map,
        }
      },
    },
  }) satisfies RollupPlugin

  nuxt.hook('nitro:build:before', (nitro) => {
    nitro.options.rollupConfig = defu(nitro.options.rollupConfig, {
      plugins: [nitroPlugin],
    })
  })

  return {
    name: 'nuxt:sourcemap-export',
    applyToEnvironment: (environment) => {
      return environment.name === 'ssr' && environment.config.isProduction
    },
    apply (config) {
      return !!config.build?.sourcemap
    },
    configResolved (config) {
      outputDir = config.build.outDir
    },
    async writeBundle (_options, bundle) {
      for (const chunk of Object.values(bundle)) {
        if (chunk.type !== 'chunk' || !chunk.map) { continue }

        const id = resolve(outputDir, chunk.fileName)
        ids.add(id)
        const dest = id + '.map.json'
        await mkdir(dirname(dest), { recursive: true })
        await writeFile(dest, JSON.stringify({
          file: chunk.map.file,
          mappings: chunk.map.mappings,
          names: chunk.map.names,
          sources: chunk.map.sources,
          sourcesContent: chunk.map.sourcesContent,
          version: chunk.map.version,
        }))
      }
    },
  }
}
